import math

def solve_tsp_dp(dist_matrix):
    n = len(dist_matrix)

    INF = float('inf')
    dp = [[INF] * n for _ in range(1 << n)]

    dp[1][0] = 0

    for mask in range(1, 1 << n):
        if not (mask & (1 << 0)):
            continue

        for i in range(n):
            if not (mask & (1 << i)):
                continue

            if mask == (1 << 0) and i == 0:
                continue

            if i == 0:
                continue

            for j in range(n):
                if j == i:
                    continue

                if not (mask & (1 << j)):
                    continue

                prev_mask = mask ^ (1 << i)

                if j == 0:
                    if prev_mask == (1 << 0) and dp[prev_mask][0] != INF:
                        dp[mask][i] = min(dp[mask][i], dp[prev_mask][0] + dist_matrix[0][i])
                else:
                    if dp[prev_mask][j] != INF:
                        dp[mask][i] = min(dp[mask][i], dp[prev_mask][j] + dist_matrix[j][i])

    min_tour_cost = INF
    final_mask = (1 << n) - 1

    for i in range(1, n): 
        if dp[final_mask][i] != INF:
            min_tour_cost = min(min_tour_cost, dp[final_mask][i] + dist_matrix[i][0])

    return min_tour_cost
